[{"fieldname": "print_heading_template", "fieldtype": "Custom HTML", "options": "<div></div>"}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<style>
.print-format {
    font-family: Arial, sans-serif;
    font-size: 11px;
    color: #000;
}
.header-table, .info-table, .items-table, .total-table {
    width: 100%;
    border-collapse: collapse;
}
.invoice-title {
    border: 1px solid #000;
    text-align: center;
    font-size: 24px;
    letter-spacing: 12px;
    padding: 5px;
    margin-top: 10px;
}
.info-table td {
    border: 1px solid #000;
    padding: 6px;
    vertical-align: top;
}
.items-table th, .items-table td {
    border: 1px solid #000;
    padding: 4px;
    vertical-align: top;
}
.items-table th {
    background: #d9d9d9;
    text-align: center;
    font-weight: bold;
}
.items-table tbody td { min-height: 30px; }
.items-table th {
    background: #d9d9d9;
    text-align: center;
    font-weight: bold;
}
.text-right { text-align: right; }
.text-center { text-align: center; }
.total-table td {
    border: 1px solid #000;
    padding: 5px;
}
.total-label {
    background: #d9d9d9;
    font-weight: bold;
}
.footer-sign {
    margin-top: 12px;
    font-weight: bold;
}
</style>

<table class="header-table">
    <tr>
        <td style="width:19%; text-align:center;">
            {% set company_logo = frappe.db.get_value('Company', doc.company, 'company_logo') %}
{% if company_logo %}
<img src="{{ company_logo }}" style="max-width:95px; max-height:95px;">
{% else %}
<div style="width:95px; height:95px; background:#f0f0f0; display:flex; align-items:center; justify-content:center; font-size:10px; color:#888;">No Logo</div>
{% endif %}
        </td>
        <td style="width:52%; text-align:left; vertical-align:middle;">
            <div style="font-size:17px; font-weight:bold; direction:rtl; text-align:left; border-bottom:2px solid #1687bd; display:inline-block; padding-bottom:3px; color:#1687bd;">
                اي كيه اتش للاستثمارات العقارية - ذ.م.م - ش.ش. و
            </div>
            <div style="font-size:17px; font-weight:bold; color:#1687bd; margin-top:6px; line-height:1.25;">
                IKH REAL ESTATE INVESTMENTS<br>L.L.C - S.P.C
            </div>
        </td>
        <td style="width:30%; color:#1687bd; font-size:12px; font-weight:bold; line-height:1.4; white-space:nowrap;">
            TRN:100278832900003<br>
            Tel +971 2 6265959<br>
            Fax +971 2 6265991<br>
            P.O.Box: 4358, AUH, UAE<br>
            Website www.alkhajaholding.com<br>
            Email info@alkhajaholding.com
        </td>
    </tr>
</table>

<div class="invoice-title">TAX INVOICE</div>

<table class="info-table" style="margin-top:6px;">
    <tr>
        <td style="width:56%;">
            <b>ID</b> &nbsp;&nbsp; {{ doc.customer or "" }}<br><br>
            <b>M/S</b> {{ doc.customer_name or "" }}<br>
            <b>TRN</b> {{ doc.tax_id or "" }}<br>
            {{ frappe.db.get_value("Address", doc.customer_address, "address_line1") or "" }}
            {{ frappe.db.get_value("Address", doc.customer_address, "address_line2") or "" }}
            {{ frappe.db.get_value("Address", doc.customer_address, "city") or "" }}
            {{ frappe.db.get_value("Address", doc.customer_address, "country") or "" }}<br>
            <b>Attn</b> {{ doc.contact_display or "" }}<br>
            <b>Tel</b> {{ doc.phone or "" }}<br>
            <b>Fax</b> {{ doc.fax or "" }}
        </td>
        <td style="width:44%;">
            <b>Invoice</b> &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; {{ doc.name }}<br><br>
            <b>Date</b> &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; {{ frappe.utils.formatdate(doc.posting_date) }}<br><br>
            <b>Customer PO No</b> &nbsp;&nbsp; {{ doc.po_no or "" }}<br><br>
            <b>Contact</b> &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; {{ doc.contact_person or "" }}<br><br>
            <b>Tel</b> &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; {{ doc.contact_mobile or "" }}<br><br>
            <b>Payment Terms</b> &nbsp;&nbsp; {{ doc.payment_terms_template or "" }}
        </td>
    </tr>
</table>

<table class="items-table" style="margin-top:8px;">
    <thead>
        <tr>
            <th style="width:4%;">#</th>
            <th style="width:31%;">Item Number and Description</th>
            <th style="width:13%;">Location</th>
            <th style="width:9%;">From</th>
            <th style="width:9%;">To</th>
            <th style="width:8%;">QTY</th>
            <th style="width:11%;">Unit Price</th>
            <th style="width:10%;">VAT</th>
            <th style="width:12%;">Amount</th>
        </tr>
    </thead>
    <tbody>
        {% for item in doc.items %}
        <tr>
            <td class="text-center">{{ loop.index }}</td>
            <td>
                <b>{{ item.item_code or "" }}</b><br>
                {{ item.item_name or "" }}<br>
                {{ item.description or "" }}
            </td>
            <td>{{ item.location or doc.lease or "" }}</td>
            <td class="text-center">
                {% if doc.from_date %}{{ frappe.utils.formatdate(doc.from_date) }}{% endif %}
            </td>
            <td class="text-center">
                {% if doc.to_date %}{{ frappe.utils.formatdate(doc.to_date) }}{% endif %}
            </td>
            <td class="text-center">
                {{ item.qty }}<br>{{ item.uom or "" }}
            </td>
            <td class="text-right">
                {{ frappe.utils.fmt_money(item.rate, currency=doc.currency) }}
            </td>
            <td class="text-right">
                {% set vat = 0 %}
                {% if doc.total_taxes_and_charges %}
                    {% set vat = doc.total_taxes_and_charges %}
                {% endif %}
                {{ frappe.utils.fmt_money(vat, currency=doc.currency) }}
            </td>
            <td class="text-right">
                <b>{{ frappe.utils.fmt_money(item.amount, currency=doc.currency) }}</b>
            </td>
        </tr>
        {% endfor %}
    </tbody>
</table>

<table style="width:100%; border-collapse:collapse;">
    <tr>
        <td style="width:68%; border-left:1px solid #000; border-bottom:1px solid #000; padding:5px;">
            {{ doc.in_words or "" }}<br>
            <b>Received By</b><br><br>
            <b>{{ doc.customer_name or "" }}</b>
        </td>
        <td style="width:32%; vertical-align:top;">
            <table class="total-table">
                <tr>
                    <td class="total-label">Subtotal</td>
                    <td class="text-right">{{ frappe.utils.fmt_money(doc.net_total, currency=doc.currency) }}</td>
                </tr>
                <tr>
                    <td class="total-label">Trade Discount</td>
                    <td class="text-right">{{ frappe.utils.fmt_money(doc.discount_amount or 0, currency=doc.currency) }}</td>
                </tr>
                <tr>
                    <td class="total-label">VAT</td>
                    <td class="text-right">{{ frappe.utils.fmt_money(doc.total_taxes_and_charges or 0, currency=doc.currency) }}</td>
                </tr>
                <tr>
                    <td class="total-label">Total Amount</td>
                    <td class="text-right"><b>{{ frappe.utils.fmt_money(doc.grand_total, currency=doc.currency) }}</b></td>
                </tr>
            </table>
            <div class="footer-sign">For {{ doc.company }}</div>
        </td>
    </tr>
</table>"}]
